<template>
  <div class="local-material">
    <el-row v-if="categoryList && categoryList.length > 0" :gutter="10" class="main-content-row">
      <el-col :span="6" class="sidebar-col">
        <!-- 左侧分类导航 -->
        <SlideLeftTwo ref="slideLeftRef" :categoryList="categoryList" @handleParams="handleQuery" :collectionStatus="false" />
      </el-col>

      <!-- 右侧素材展示区（3列网格） -->
      <el-col :span="18" class="content-col">
        <div class="content">
          <div class="content-image" v-for="item in materialAllList" :key="item.id">
            <img :src="item.thumbnail" @click="handleDownload(item)" style="width: 100%; height: 100%; object-fit: cover; border-radius: 10%" />
          </div>
        </div>
      </el-col>
    </el-row>
    <el-image v-else :src="localMaterialImg" style="margin-top: 5px; width: 100%; height: 100%; contain: conver" />
  </div>
</template>

<script>
import SlideLeftTwo from '@/components/SlideLeftTwo.vue';
import { getSettingInfo } from '@/api/main';
import { getCommonLocalFolderList, getCommonLocalFileList, openLocalFile } from '@/utils/cepio';

export default {
  name: 'LocalMaterial',
  components: {
    SlideLeftTwo
  },
  props: {
    localMaterialImg: {
      type: String,
      default: require('@/assets/logo.png')
    }
  },
  data() {
    return {
      materialAllList: [],
      categoryList: []
    };
  },
  created() {
    this.getSettingInfos();
  },
  methods: {
    async getSettingInfos() {
      const response = await getSettingInfo();
      const localMaterialPath = (response.data && response.data.localMaterialPath) || null;
      if (localMaterialPath) {
        await this.getCategories(localMaterialPath);
      }
    },
    async getCategories(localFolderAddress) {
      const response = await getCommonLocalFolderList(localFolderAddress);
      this.categoryList = response || [];
    },
    async handleQuery(params) {
      await this.getMaterials(params.categoryId);
    },
    async getMaterials(localFolderAddress) {
      const response = await getCommonLocalFileList(localFolderAddress);
      this.materialAllList = response || [];
    },
    async handleDownload(item) {
      openLocalFile('localEmbedImageToMockup', item.thumbnail, null);
    },
    refreshLocalMaterial() {
      this.materialAllList = [];
      this.categoryList = [];
      // 刷新本地素材列表
      this.getSettingInfos();
    }
  }
};
</script>

