.local-material {
  background-color: black;
  display: flex;
  flex-direction: column;
  height: calc(92vh);
}
.main-content-row {
  flex: 1;
  height: calc(92vh); /* 减去搜索框高度 */
  overflow: hidden;
}
.sidebar-col,
.content-col {
  background-color: black;
  height: calc(92vh); /* 减去搜索框高度 */
}
.content {
  margin-top: 10px;
  overflow-y: auto; /* 当内容超出高度时，添加垂直滚动条 */
  cursor: pointer;
  display: flex;
  flex-wrap: wrap;
  gap: 20px; /* 同时控制行间距和列间距 */
  justify-content: flex-start; /* 修改为：从顶部开始排列，不留空隙 */
  align-content: flex-start; /* 如果是多行，确保行也是从顶部开始 */
  padding-bottom: 20px; /* 添加底部间距 */
  height: 100%;
  box-sizing: border-box;
}

.content-image {
  margin: 5px;
  flex: 0 0 calc(50% - 15px);
  max-width: calc(50% - 15px);
  border: 1px solid #f0f2f5;
  border-radius: 10%;
  height: 100px;
  display: flex;
  flex-direction: column;
  position: relative;
}
</style>
